import os
import pickle
import json
import boto3
import requests
from pathlib import Path
import tempfile
import shutil

class ModelLoader:
    def __init__(self):
        self.model_path = os.environ.get('MODEL_PATH', 's3://models/default')
        self.local_cache = tempfile.mkdtemp()
        self.model = None
        
    def load_from_s3(self, bucket, key):
        s3 = boto3.client('s3')
        local_file = os.path.join(self.local_cache, os.path.basename(key))
        s3.download_file(bucket, key, local_file)
        with open(local_file, 'rb') as f:
            return pickle.load(f)
    
    def load_from_gcs(self, bucket, blob_name):
        from google.cloud import storage
        client = storage.Client()
        bucket_obj = client.bucket(bucket)
        blob = bucket_obj.blob(blob_name)
        local_file = os.path.join(self.local_cache, os.path.basename(blob_name))
        blob.download_to_filename(local_file)
        with open(local_file, 'rb') as f:
            return pickle.load(f)
    
    def load_from_http(self, url):
        response = requests.get(url)
        local_file = os.path.join(self.local_cache, 'model.pkl')
        with open(local_file, 'wb') as f:
            f.write(response.content)
        with open(local_file, 'rb') as f:
            return pickle.load(f)
    
    def get_latest_version_s3(self, bucket, prefix):
        s3 = boto3.client('s3')
        response = s3.list_objects_v2(Bucket=bucket, Prefix=prefix)
        if 'Contents' not in response:
            return None
        objects = sorted(response['Contents'], key=lambda x: x['LastModified'], reverse=True)
        return objects[0]['Key'] if objects else None
    
    def get_latest_version_gcs(self, bucket, prefix):
        from google.cloud import storage
        client = storage.Client()
        bucket_obj = client.bucket(bucket)
        blobs = list(bucket_obj.list_blobs(prefix=prefix))
        if not blobs:
            return None
        latest = sorted(blobs, key=lambda x: x.updated, reverse=True)[0]
        return latest.name
    
    def load_model(self):
        path = self.model_path
        
        if path.startswith('s3://'):
            parts = path[5:].split('/', 1)
            bucket = parts[0]
            prefix = parts[1] if len(parts) > 1 else ''
            
            key = self.get_latest_version_s3(bucket, prefix)
            if not key:
                key = prefix
            
            self.model = self.load_from_s3(bucket, key)
            
        elif path.startswith('gs://'):
            parts = path[5:].split('/', 1)
            bucket = parts[0]
            prefix = parts[1] if len(parts) > 1 else ''
            
            blob_name = self.get_latest_version_gcs(bucket, prefix)
            if not blob_name:
                blob_name = prefix
            
            self.model = self.load_from_gcs(bucket, blob_name)
            
        elif path.startswith('http://') or path.startswith('https://'):
            self.model = self.load_from_http(path)
            
        else:
            with open(path, 'rb') as f:
                self.model = pickle.load(f)
        
        return self.model
    
    def predict(self, data):
        if self.model is None:
            raise RuntimeError("Model not loaded")
        return self.model.predict(data)

def main():
    loader = ModelLoader()
    model = loader.load_model()
    print(f"Model loaded successfully from {loader.model_path}")
    return loader

if __name__ == '__main__':
    main()